import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"钉影射钉枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/钉影射钉枪.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/钉影射钉枪.md"}'),p={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/钉影射钉枪.md"};function d(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"钉影射钉枪",tabindex:"-1"},[s("钉影射钉枪 "),e("a",{class:"header-anchor",href:"#钉影射钉枪","aria-label":'Permalink to "钉影射钉枪"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),o('<h1 id="钉影射钉枪-1" tabindex="-1">钉影射钉枪 <a class="header-anchor" href="#钉影射钉枪-1" aria-label="Permalink to &quot;钉影射钉枪&quot;">​</a></h1><p>钉影射钉枪<br> c+1000<br> 特异本质<br> 类型：武器/射钉枪（自动手枪）</p><p>这是一把能够钉住影子的射钉枪，但射钉枪不重要，钉子也不重要，能射出钉子钉住影子，这才是最重要的。</p><p>传说，有一种影子怪物，它会完美的模拟成生命的样子，但影子就是它们的弱点，钉住，锤击，射击，穿刺，都会对他们造成伤害与影响。</p><p>这并非原本的那把射钉枪，而是由钉住影子得来的概念形成的钉影射钉枪，就像原本的射钉枪只是因为钉住过影子而特殊，而它，是因为能钉住影子而特殊。</p><p>武器伤害11L 高速5 穿刺 短点射 体积2 装弹11+1 射程30米</p><p>【钉影】<br>   如果在你射击时，如果对方的影子与本体处于你的攻击范围内，并且你的效果线未被阻挡时，你可以选择以一个自由动作将目标转为对对目标的影子进行攻击，这会使得你的本次攻击不造成伤害，而是将攻击点数转化为纠缠点数并且反应到影子的主人身上，目标本体需以强韧豁免来豁免该纠缠点数，并且在豁免时，会使其拥有的能量池中的1点任意能量流失。<br>   同时，以此武器对影子进行部位攻击时，视为对目标的特殊部位攻击减值忽略2点，若目标在这次攻击中承受了纠缠点数，则对其施加d级创伤来源困难地形效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
